const state=readJson(path.join(base,'treatment-generic-refactor-state.json'));
let evaluatorOutput=null;
let evaluatorOutputFound=false;
let evaluatorVerdict='';
const stdoutPath=path.join(base,'sdk-stage-logs/generic-refactor-evaluator-stdout.log');
if (fs.existsSync(stdoutPath)) {
  try {
    evaluatorOutput=JSON.parse(fs.readFileSync(stdoutPath,'utf8'));
    evaluatorOutputFound=true;
    evaluatorVerdict=evaluatorOutput.verdict || evaluatorOutput.status || '';
  } catch {}
}
const candidates=[
  path.join(run,'artifacts/eval-report.json'),
  path.join(run,'artifacts/final-eval-report.json'),
  path.join(base,'sdk-stage-logs/generic-refactor-evaluator-stdout.log')
];
const evaluatorArtifactPathsFound=candidates.filter(p=>fs.existsSync(p));
const evalReportPath=fs.existsSync(path.join(run,'artifacts/eval-report.json'))?'artifacts/eval-report.json':'';
const finalReportPath=fs.existsSync(path.join(run,'artifacts/FinalDeliveryReport.md'))?'artifacts/FinalDeliveryReport.md':'';
