  danger_full_access_used: treatment.danger_full_access_used === true,
  m12_gate_status: 'PASS',
  production_ready: false
};
writeFileSync(`${reportDir}/canary-pass-summary.json`, `${JSON.stringify(summary, null, 2)}\n`, 'utf8');
writeFileSync(`${reportDir}/CanaryPassSummary.md`, [
  '# M12 test-coverage-002 Canary PASS Summary',
  '',
  'Status: PASS',
  '',
  'test-coverage-002 now has real baseline and real SDK-Orchestrated treatment evidence. The treatment completed through the direct evaluator PASS path:',
  '',
  'Planner -> Dev Worker -> Evaluator PASS -> FinalReport',
  '',
  '## Evidence',
  `- Baseline real run executed: ${summary.baseline_real_run_executed}`,
  `- Treatment real run executed: ${summary.treatment_real_run_executed}`,
